#[derive(Debug, Serialize, Deserialize)]
pub struct CacheIndex {
    pub entries: HashMap<String, String>, // user_id -> filename
}

pub struct DiskCache {
    cache_dir: PathBuf,
    index: CacheIndex,
}

impl DiskCache {
    pub fn new<P: AsRef<Path>>(cache_dir: P) -> Result<Self, CacheError> {
        let cache_dir = cache_dir.as_ref().to_path_buf();
        fs::create_dir_all(&cache_dir)?;

        let index_path = cache_dir.join("index.bin");
        let index = if index_path.exists() {
            let data = fs::read(&index_path)?;
            bincode::deserialize(&data)?
        } else {
            CacheIndex {
                entries: HashMap::new(),
            }
        };

        Ok(DiskCache { cache_dir, index })
    }

    fn save_index(&self) -> Result<(), CacheError> {
        let index_path = self.cache_dir.join("index.bin");
        let data = bincode::serialize(&self.index)?;
        fs::write(&index_path, data)?;
        Ok(())
    }

    fn get_file_path(&self, user_id: &str) -> PathBuf {
        let sanitized = user_id.replace(|c: char| !c.is_alphanumeric() && c != '_' && c != '-', "_");
        self.cache_dir.join(format!("{}.bin", sanitized))
    }

    pub fn save(&mut self, prefs: &UserPreferences) -> Result<(), CacheError> {
        let file_path = self.get_file_path(&prefs.user_id);
        let data = bincode::serialize(prefs)?;
        fs::write(&file_path, data)?;

        self.index.entries.insert(
            prefs.user_id.clone(),
            file_path.file_name().unwrap().to_string_lossy().to_string(),
        );
        self.save_index()?;

        Ok(())
    }

    pub fn load(&self, user_id: &str) -> Result<UserPreferences, CacheError> {
        if !self.index.entries.contains_key(user_id) {
            return Err(CacheError::NotFound(user_id.to_string()));
        }

        let file_path = self.get_file_path(user_id);
        if !file_path.exists() {
            return Err(CacheError::NotFound(user_id.to_string()));
        }

        let data = fs::read(&file_path)?;
        let prefs: UserPreferences = bincode::deserialize(&data)?;
        Ok(prefs)
    }

    pub fn delete(&mut self, user_id: &str) -> Result<(), CacheError> {
        let file_path = self.get_file_path(user_id);
        if file_path.exists() {
            fs::remove_file(&file_path)?;
        }
        self.index.entries.remove(user_id);
        self.save_index()?;
        Ok(())
    }

    pub fn list_users(&self) -> Vec<String> {
        self.index.entries.keys().cloned().collect()
    }

    pub fn contains(&self, user_id: &str) -> bool {
        self.index.entries.contains_key(user_id)
    }

    pub fn clear(&mut self) -> Result<(), CacheError> {
        for (user_id, _) in self.index.entries.drain() {
            let file_path = self.get_file_path(&user_id);
            if file_path.exists() {
                fs::remove_file(&file_path)?;
            }
        }
        // Re-initialize index as empty since drain consumed all entries
        self.index.entries = HashMap::new();
        self.save_index()?;
        Ok(())
    }

    pub fn save_all(&mut self, prefs_list: &[UserPreferences]) -> Result<(), CacheError> {
        for prefs in prefs_list {
            self.save(prefs)?;
        }
        Ok(())
    }

    pub fn load_all(&self) -> Result<Vec<UserPreferences>, CacheError> {
        let mut results = Vec::new();
        for user_id in self.index.entries.keys() {
            match self.load(user_id) {
                Ok(prefs) => results.push(prefs),
                Err(CacheError::NotFound(_)) => continue,
                Err(e) => return Err(e),
            }
        }
        Ok(results)
    }
}

